from datetime import datetime, timedelta

def attack_timeline() -> dict:
    attack_date = datetime(2022, 7, 30)
    return {
        'sidh_proposal': datetime(2011, 1, 1),
        'sike_nist': datetime(2017, 11, 30),
        'attack': attack_date,
        'verification': attack_date + timedelta(hours=24),
        'improvements': attack_date + timedelta(days=7),
        'withdrawal': attack_date + timedelta(days=30)
    }

def days_to_break_after_proposal(proposal_year: int = 2011) -> int:
    return (datetime(2022, 7, 30) - datetime(proposal_year, 1, 1)).days

