exercises.solution:
import math

def auxiliary_bits(p_bits: int) -> int:
    # Two points, each with x,y coords over F_p²
    # Each coord is 2 * p_bits (F_p² element)
    return 2 * 4 * p_bits  # 8 * p_bits total

def secret_bits(a: int) -> int:
    # Secret is essentially a bits
    return a

def info_ratio(p_bits: int, a: int) -> float:
    return auxiliary_bits(p_bits) / secret_bits(a)

