exercises.solution:
def categorize_lessons() -> dict:
    return {
        'data_minimization': 'Publish minimum auxiliary data',
        'assumption_match': 'Security assumption must match protocol',
        'interdisciplinary': 'Attacks can come from unexpected math areas',
        'conservatism': 'Novel structures have unknown risks',
        'humility': 'No scheme is proven secure'
    }

def applies_to_scheme(scheme: str) -> list:
    all_lessons = list(categorize_lessons().keys())
    if scheme.lower() == 'sidh':
        return all_lessons
    elif scheme.lower() in ['kyber', 'dilithium']:
        return ['assumption_match', 'humility']
    return ['humility']
